# =============================================================================
# Tests for KitaevHoneycomb matter-sector finite-temperature observables.
#
# Implementation: KitaevHoneycomb_thermal.jl evaluates the matter-Majorana
# free-fermion partition function generated by the flux-free-sector Bloch
# Hamiltonian (`О»_k = |f(k)|`).  The ZвӮӮ flux degrees of freedom are *not*
# thermalised вҖ” this is the standard matter-sector approximation, valid
# for `T вүӘ О”_v` (`О”_v вүҲ 0.07 |K|` at the isotropic gapless point; larger
# in the gapped A-phases).
#
# Layers:
#   1. T вҶ’ 0 (ОІ=80) consistency: thermal observables match GS values from
#      `KitaevHoneycomb.jl`.
#   2. T вҶ’ вҲһ (ОІ=1e-4) analytic limits: matter sector is one Majorana mode
#      per unit cell (= 1 fermion mode per 2 sites), so the per-site
#      entropy saturates at log(2)/2 вүҲ 0.34657...
#   3. Thermodynamic identities (Оө = f + TВ·s, c_v = -ОІВІ вҲӮОө/вҲӮОІ via
#      ForwardDiff) at gapless isotropic point вҖ” both Infinite and OBC.
#   4. OBC вҶ’ Infinite convergence: per-site free energy converges as
#      Lx = Ly grow (gapless point вҮ’ algebraic boundary effects).
#   5. Phase smoke test: c_v finite & positive in both gapless (B-phase)
#      and gapped (A_z) parameter regimes.
# =============================================================================

using QAtlas
using QAtlas:
    KitaevHoneycomb, Energy, FreeEnergy, ThermalEntropy, SpecificHeat, OBC, Infinite
using Test
using LinearAlgebra
using ForwardDiff

@testset "KitaevHoneycomb matter-sector thermal observables" begin

    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Layer 1: T вҶ’ 0 consistency (ОІ large).
    #
    # The thermal formulas use the convention `Z = вҲҸ 2 cosh(ОІ О»_k / 2)`
    # (single-fermion levels at `ВұО»_k/2`), which gives a per-site GS
    # of `-ОЈ О»_k / (4 Lx Ly)` (Infinite: `-(1/(2В·(2ПҖ)ВІ))В·вҲ«(О»/2)dВІОё`).
    # The thermal and GS paths share the *same* matter-Majorana
    # convention: single complex-fermion levels at `ВұПғ_k`, giving
    # `Z_k = 2 cosh(ОІПғ_k)` and `Оө(ОІвҶ’вҲһ) = -ОЈ Пғ_k / N_sites` per site,
    # which exactly matches the GS routine's `-ОЈ Пғ_k / (2 Lx Ly)`.
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    @testset "T вҶ’ 0 consistency (ОІ=80)" begin
        m = KitaevHoneycomb(; Kx=1.0, Ky=1.0, Kz=1.0)
        ОІ_low = 80.0

        # Self-consistency: Оө_thermal(ОІ=80) вүҲ f_thermal(ОІ=80) (entropy
        # term is small).  Both Infinite and OBC.
        Оө_th_inf = QAtlas.fetch(m, Energy(:per_site), Infinite(); beta=ОІ_low)
        f_th_inf = QAtlas.fetch(m, FreeEnergy(), Infinite(); beta=ОІ_low)
        @test Оө_th_inf вүҲ f_th_inf rtol = 1e-2

        Оө_th_obc = QAtlas.fetch(m, Energy(:per_site), OBC(0); Lx=4, Ly=4, beta=ОІ_low)
        f_th_obc = QAtlas.fetch(m, FreeEnergy(), OBC(0); Lx=4, Ly=4, beta=ОІ_low)
        @test Оө_th_obc вүҲ f_th_obc rtol = 1e-2

        # Cross-validation against GS routine вҖ” must agree at large ОІ
        # (entropy correction `O(exp(-ОІ О”))` for the gapped phase, only
        # algebraic at the gapless isotropic point so we use a loose
        # rtol = 1e-3).
        Оө_gs_inf = QAtlas.fetch(m, Energy(), Infinite())
        @test Оө_th_inf вүҲ Оө_gs_inf rtol = 1e-3
        Оө_gs_obc = QAtlas.fetch(m, Energy(), OBC(0); Lx=4, Ly=4)
        @test Оө_th_obc вүҲ Оө_gs_obc rtol = 1e-3

        # Gapless point: Dirac modes give algebraic decay of s, c_v.
        # Loose bounds (still tiny vs O(1) high-T values).
        s_inf = QAtlas.fetch(m, ThermalEntropy(), Infinite(); beta=ОІ_low)
        @test abs(s_inf) < 1e-3
        c_inf = QAtlas.fetch(m, SpecificHeat(), Infinite(); beta=ОІ_low)
        @test abs(c_inf) < 1e-3

        # Gapped Az phase: all О»_k вүҘ О” = 2(Kz - Kx - Ky) > 0, so
        # entropy / specific heat vanish exponentially.  This works
        # regardless of the convention factor of 2.
        m_gapped = KitaevHoneycomb(; Kx=0.5, Ky=0.5, Kz=2.0)
        s_inf_g = QAtlas.fetch(m_gapped, ThermalEntropy(), Infinite(); beta=ОІ_low)
        @test abs(s_inf_g) < 1e-10
        c_inf_g = QAtlas.fetch(m_gapped, SpecificHeat(), Infinite(); beta=ОІ_low)
        @test abs(c_inf_g) < 1e-10
        s_obc_g = QAtlas.fetch(m_gapped, ThermalEntropy(), OBC(0); Lx=4, Ly=4, beta=ОІ_low)
        @test abs(s_obc_g) < 1e-10
        c_obc_g = QAtlas.fetch(m_gapped, SpecificHeat(), OBC(0); Lx=4, Ly=4, beta=ОІ_low)
        @test abs(c_obc_g) < 1e-10
    end

    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Layer 2: T вҶ’ вҲһ analytic limits.
    #
    # Matter sector has LxВ·Ly modes per LxВ·Ly unit cells (= N_sites/2 modes
    # in total), each contributing log(2) of entropy at infinite T.  Per-site
    # entropy thus saturates at log(2)/2.  c_v vanishes вҲқ ОІВІ as the modes
    # decouple from the thermal bath.
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    @testset "T вҶ’ вҲһ analytic limits (ОІ=1e-4)" begin
        m = KitaevHoneycomb(; Kx=1.0, Ky=1.0, Kz=1.0)
        ОІ_high = 1e-4

        # Per-site entropy вҶ’ log(2)/2
        s_inf = QAtlas.fetch(m, ThermalEntropy(), Infinite(); beta=ОІ_high)
        @test s_inf вүҲ log(2) / 2 atol = 1e-6

        s_obc = QAtlas.fetch(m, ThermalEntropy(), OBC(0); Lx=4, Ly=4, beta=ОІ_high)
        @test s_obc вүҲ log(2) / 2 atol = 1e-6

        # Free energy per site at ОІ вҶ’ 0:  f вҶ’ -T В· log(2)/2
        f_inf = QAtlas.fetch(m, FreeEnergy(), Infinite(); beta=ОІ_high)
        @test f_inf вүҲ -log(2) / (2 * ОІ_high) atol = 1e-3 / ОІ_high

        # Specific heat вҶ’ 0 at ОІ вҶ’ 0 (quadratic in ОІ)
        c_inf = QAtlas.fetch(m, SpecificHeat(), Infinite(); beta=ОІ_high)
        @test abs(c_inf) < 1e-6
        c_obc = QAtlas.fetch(m, SpecificHeat(), OBC(0); Lx=4, Ly=4, beta=ОІ_high)
        @test abs(c_obc) < 1e-6
    end

    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Layer 3: Thermodynamic identities at the gapless isotropic point.
    # Hand-rolled identity check (the harness in
    # `test/util/thermodynamic_identities.jl` reads `bc.N` for OBC, but
    # KitaevHoneycomb OBC takes `Lx, Ly` kwargs instead).
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    @testset "thermodynamic identities (Infinite)" begin
        m = KitaevHoneycomb(; Kx=1.0, Ky=1.0, Kz=1.0)
        for ОІ in (0.5, 1.0, 2.0)
            Оө = QAtlas.fetch(m, Energy(:per_site), Infinite(); beta=ОІ)
            f = QAtlas.fetch(m, FreeEnergy(), Infinite(); beta=ОІ)
            s = QAtlas.fetch(m, ThermalEntropy(), Infinite(); beta=ОІ)
            @test Оө вүҲ f + s / ОІ atol = 1e-9

            dОө = ForwardDiff.derivative(
                b -> QAtlas.fetch(m, Energy(:per_site), Infinite(); beta=b), ОІ
            )
            c = QAtlas.fetch(m, SpecificHeat(), Infinite(); beta=ОІ)
            @test c вүҲ -ОІ^2 * dОө rtol = 1e-3
        end
    end

    @testset "thermodynamic identities (OBC 4Г—4)" begin
        m = KitaevHoneycomb(; Kx=1.0, Ky=1.0, Kz=1.0)
        Lx, Ly = 4, 4
        for ОІ in (0.5, 1.0, 2.0)
            Оө = QAtlas.fetch(m, Energy(:per_site), OBC(0); Lx=Lx, Ly=Ly, beta=ОІ)
            f = QAtlas.fetch(m, FreeEnergy(), OBC(0); Lx=Lx, Ly=Ly, beta=ОІ)
            s = QAtlas.fetch(m, ThermalEntropy(), OBC(0); Lx=Lx, Ly=Ly, beta=ОІ)
            @test Оө вүҲ f + s / ОІ atol = 1e-9

            dОө = ForwardDiff.derivative(
                b -> QAtlas.fetch(m, Energy(:per_site), OBC(0); Lx=Lx, Ly=Ly, beta=b), ОІ
            )
            c = QAtlas.fetch(m, SpecificHeat(), OBC(0); Lx=Lx, Ly=Ly, beta=ОІ)
            @test c вүҲ -ОІ^2 * dОө rtol = 1e-3
        end
    end

    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Layer 4: OBC вҶ’ Infinite convergence (Lx = Ly grows, ОІ fixed).
    # The gapless isotropic point has algebraic boundary effects, so
    # convergence is slower than the gapped TFIM disordered phase.
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    @testset "OBC вҶ’ Infinite convergence (gapless isotropic)" begin
        m = KitaevHoneycomb(; Kx=1.0, Ky=1.0, Kz=1.0)
        ОІ = 1.0
        f_inf = QAtlas.fetch(m, FreeEnergy(), Infinite(); beta=ОІ)
        Ls = (4, 8, 16)
        errs = Float64[]
        for L in Ls
            f_obc = QAtlas.fetch(m, FreeEnergy(), OBC(0); Lx=L, Ly=L, beta=ОІ)
            push!(errs, abs(f_obc - f_inf))
        end
        # Largest box: |О”f| < 3e-2 вҖ” gapless point has algebraic
        # (not exponential) boundary effects in 2D; 16Г—16 still leaves
        # a measurable residual.  This is well below |f_inf| вүҲ 1.
        @test errs[end] < 3e-2
        # Convergence: 16Г—16 error strictly smaller than 4Г—4 error.
        @test errs[end] < errs[1]
    end

    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    # Layer 5: Phase smoke test вҖ” c_v positive, finite in both phases.
    # в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
    @testset "phase smoke test: c_v positive & finite" begin
        m_gapless = KitaevHoneycomb(; Kx=1.0, Ky=1.0, Kz=1.0)
        m_gapped = KitaevHoneycomb(; Kx=0.5, Ky=0.5, Kz=2.0)
        for ОІ in (0.5, 1.0, 2.0)
            for m in (m_gapless, m_gapped)
                c_inf = QAtlas.fetch(m, SpecificHeat(), Infinite(); beta=ОІ)
                @test isfinite(c_inf)
                @test c_inf > 0
                c_obc = QAtlas.fetch(m, SpecificHeat(), OBC(0); Lx=4, Ly=4, beta=ОІ)
                @test isfinite(c_obc)
                @test c_obc > 0
            end
        end
    end
end
